-- =====================================================
-- 2. Структурированные критерии перехода shoulder_frozen
--    (JOIN на rehab_phases по program_type+phase_number → реальный phase_id)
--    Phase 0 отсутствует. Фазы 1–3 несут критерии (терминальная фаза 3 — критерии выписки).
--    measurement = боль ВАШ (vas_score+pain) ТОЛЬКО (один критерий: боль в покое ≤4 при 1→2);
--    объём/градусы/%/сила → instructor_check (число в ТЕКСТЕ label).
-- =====================================================
WITH criteria_data (
  phase_number, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2,
  staleness_days, self_report_question, self_report_hint,
  position, is_required
) AS (VALUES
  -- Фаза 1 → Фаза 2 (болевая фаза → фаза тугоподвижности)
  (1, 'night_pain_reduced_p1', 'Уменьшились ночные пробуждения от боли по сравнению с началом',                              'self_report',      NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 7::smallint, 'Стали ли ночные пробуждения от боли реже, чем в начале?', 'Сравните, как часто боль будила вас раньше и сейчас', 10::smallint, TRUE),
  (1, 'rest_pain_milder_p1',   'Боль в покое стала слабой или умеренной, а не постоянной сильной',                          'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Боль в покое стала слабее, чем была — не постоянная сильная?', 'Оцените боль в спокойном состоянии, без движения', 20::smallint, TRUE),
  (1, 'rest_pain_le_4_p1',     'Боль в покое не более 4 из 10',                                                            'measurement',      'vas_score', 'pain', '<=', 4::numeric, NULL, 7::smallint, NULL, NULL, 30::smallint, TRUE),
  (1, 'passive_rom_stable_p1', 'Пассивная подвижность перестала уменьшаться, наметился прирост (оценка куратора)',           'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, TRUE),
  (1, 'technique_indep_p1',    'Правильная техника маятника и безболезненной гимнастики, самостоятельность в домашней программе (оценка куратора)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 50::smallint, FALSE),

  -- Фаза 2 → Фаза 3 (фаза тугоподвижности → фаза восстановления)
  (2, 'passive_flexion_120_p2', 'Пассивный подъём руки вперёд не менее 120°',                                               'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (2, 'passive_er_progress_p2', 'Поворот руки наружу заметно прогрессирует к функциональному уровню (ориентир около 30° и выше); единого порога нет — решает куратор очно', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (2, 'daily_tasks_easier_p2',  'Бытовые действия (одеться, дотянуться) стали даваться легче',                               'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Стало ли легче выполнять бытовые действия — одеться, дотянуться?', 'Сравните привычные движения сейчас и пару недель назад', 30::smallint, TRUE),
  (2, 'pain_end_range_only_p2', 'Боль преобладает только в конце амплитуды, а не на протяжении всего движения (оценка куратора)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, TRUE),
  (2, 'scapular_rhythm_p2',     'Восстанавливается слаженная работа плеча и лопатки, нет грубых компенсаций (оценка куратора)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 50::smallint, FALSE),

  -- Фаза 3 (терминальная) → завершение/выписка (критерии готовности)
  (3, 'rom_90_pct_p3',         'Амплитуда не менее 90% от здоровой стороны во всех направлениях',                            'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 10::smallint, TRUE),
  (3, 'strength_symmetric_p3', 'Сила больной руки сравнялась со здоровой (симметрична при мануальном или динамометрическом тесте)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 20::smallint, TRUE),
  (3, 'adl_work_painfree_p3',  'Повседневные и рабочие задачи выполняются без боли',                                        'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Можете выполнять повседневные и рабочие задачи без боли?', 'Оцените по реальным делам дома и на работе', 30::smallint, TRUE),
  (3, 'sleep_painfree_p3',     'Можете спать на больной стороне без пробуждений от боли',                                    'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Можете спать на больной стороне без пробуждений от боли?', 'Вспомните несколько последних ночей', 40::smallint, TRUE),
  (3, 'normal_rhythm_p3',      'Слаженная работа плеча и лопатки, нет болезненной дуги при подъёме руки в сторону (оценка куратора)', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 50::smallint, FALSE),
  (3, 'maintenance_indep_p3',  'Вы самостоятельны в поддерживающей программе',                                              'self_report',      NULL, NULL, NULL, NULL, NULL, 14::smallint, 'Можете самостоятельно поддерживать программу упражнений?', 'Оцените, справляетесь ли с упражнениями дома без подсказок', 60::smallint, TRUE)
)
INSERT INTO phase_transition_criteria (
  phase_id, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2, staleness_days,
  self_report_question, self_report_hint,
  position, is_required, is_active
)
SELECT
  p.id, cd.criterion_code, cd.label, cd.criterion_type,
  cd.measurement_type, cd.measurement_source,
  cd.threshold_operator, cd.threshold_value, cd.threshold_value2, cd.staleness_days,
  cd.self_report_question, cd.self_report_hint,
  cd.position, cd.is_required, TRUE
FROM criteria_data cd
JOIN rehab_phases p ON p.program_type = 'shoulder_frozen' AND p.phase_number = cd.phase_number
ON CONFLICT (phase_id, criterion_code) DO NOTHING;

COMMIT;
